%%%%%%%%%% Function vrnSF.m %%%%%%%%%%% Function Varian Start and Finish, ver.1% Kei Nakamura% Created on Wednesday, May 6th 2006.% Modified on %% function [strt stpN] = vrnSF(x stpV)% returns the start value and step number for plotting.function [strt stpN] = vrnSF(x,stpV)  %function headerminX = min(x);maxX = max(x);pp = 1; strt = 0;while pp~=0;    cv = minX+(pp-1.5)*stpV;   % current value    if minX>cv;        strt = cv;    end    if maxX<cv;        fns = cv;        pp = -1;    end    pp = pp + 1;endstpN = round((fns-strt)/stpV);
